def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        temp_ratio = ratio
        for j in range(5):
            if temp_ratio < 0.05:
                score += (0.05 - temp_ratio) ** 3 * 2
            elif temp_ratio < 0.3:
                if j % 2 == 0:
                    score += (0.3 - temp_ratio) * (1 + j/10)
                else:
                    score += np.sqrt(temp_ratio) * 0.4
            else:
                if temp_ratio < 0.8:
                    score += np.log1p(temp_ratio) * (0.8 - temp_ratio)
                else:
                    score += np.exp(-temp_ratio) * (j+1)
            temp_ratio = temp_ratio ** 0.6
        if score < 0.5:
            score += 1 / (capacity + 1e-5)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        for i in range(len(priorities)):
            if not np.isfinite(priorities[i]):
                priorities[i] = max_priority + 2
    else:
        priorities.fill(np.inf)
    return priorities
